from sys import stdin

def main():
    data = stdin.read().split()
    idx = 0
    n = int(data[idx]); m = int(data[idx+1]); idx += 2

    x = [0] * (n + 1)
    y = [0] * (n + 1)
    for i in range(1, n + 1):
        x[i] = int(data[idx]); y[i] = int(data[idx+1]); idx += 2

    events = []
    for _ in range(m):
        op = int(data[idx]); k = int(data[idx+1])
        events.append((op, k)); idx += 2

    active = {}
    res = []

    for day in range(1, m + 1):
        op, k = events[day - 1]
        if op == 1:
            active[k] = day
        else:
            del active[k]

        maintenance = 0
        for model, start in active.items():
            cycle = x[model] + y[model]
            offset = day - start  # 0-based: day==start => offset=0 => first working day
